var scpGeometry=freeze(new function(){var c=this;this.point=function(a){return function(b){return{x:a,y:b}}};this.line=function(a){return function(b){return[a,b]}};this.verticalPosition=function(a){return applyRv(a)};this.horizontalLine=function(a){return function(b){return function(d){return c.line(a)(b).map(c.verticalPosition(d))}}}});
